import { useState, useEffect, CSSProperties } from "react";
import API from "./API.tsx";

interface ProfilePageProps {
  onComplete: () => void;
}

export default function ProfilePage({ onComplete }: ProfilePageProps) {
  const [name, setName] = useState<string>("");
  const [email, setEmail] = useState<string>("");
  const [fetching, setFetching] = useState<boolean>(true);
  const [error, setError] = useState<string>("");

  useEffect(() => {
    const loadUser = async () => {
      try {
        const res = await API.get("auth/users/me/");
        setName(res.data.name || "");
        setEmail(res.data.email || "");
      } catch {
        setError("Could not load your profile.");
      } finally {
        setFetching(false);
      }
    };
    loadUser();
  }, []);

  if (fetching) {
    return (
      <div style={styles.loadingRoot}>
        <span style={styles.loadingSpinner} />
        <p style={styles.loadingText}>Loading your profile…</p>
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  return (
    <div style={styles.root}>
      <div style={styles.bg} aria-hidden="true" />

      <div style={styles.layout}>
        {/* ── Sidebar ── */}
        <div style={styles.sidebar}>
          <div style={styles.sidebarInner}>
            <div style={styles.logoRow}>
              <div style={styles.logoMark}>
                <svg width="22" height="22" viewBox="0 0 22 22" fill="none">
                  <rect x="1" y="1" width="9" height="9" rx="2" fill="#e8d5c4" />
                  <rect x="12" y="1" width="9" height="9" rx="2" fill="#c9b8a8" opacity="0.6" />
                  <rect x="1" y="12" width="9" height="9" rx="2" fill="#c9b8a8" opacity="0.6" />
                  <rect x="12" y="12" width="9" height="9" rx="2" fill="#e8d5c4" />
                </svg>
              </div>
              <span style={styles.logoText}>TaskFlow</span>
            </div>

            <div style={styles.avatarWrap}>
              <div style={styles.avatar}>
                {name ? name.charAt(0).toUpperCase() : "?"}
              </div>
              <p style={styles.avatarName}>{name || "—"}</p>
              <p style={styles.avatarEmail}>{email || "—"}</p>
            </div>
          </div>
        </div>

        {/* ── Display card ── */}
        <div style={styles.card}>
          <h1 style={styles.heading}>Your profile</h1>
          <p style={styles.subheading}>
            Your account details from our records.
          </p>

          {error && <div style={styles.errorBox}>{error}</div>}

          <div style={styles.fields}>
            <div style={styles.sectionLabel}>Account info</div>

            <div style={styles.row}>
              <span style={styles.rowLabel}>Full name</span>
              <span style={styles.rowValue}>{name || <em style={styles.empty}>Not set</em>}</span>
            </div>

            <div style={styles.divider} />

            <div style={styles.row}>
              <span style={styles.rowLabel}>Email address</span>
              <span style={styles.rowValue}>{email || <em style={styles.empty}>Not set</em>}</span>
            </div>
          </div>

          <div style={styles.actions}>
            <button onClick={onComplete} style={styles.continueBtn}>
              Continue →
            </button>
          </div>
        </div>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Lora:ital@0;1&family=DM+Sans:wght@400;500&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(16px); }
          to   { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
}

const styles: Record<string, CSSProperties> = {
  loadingRoot: {
    minHeight: "100vh",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    background: "#f5f0eb",
    gap: "12px",
  },
  loadingSpinner: {
    width: "28px",
    height: "28px",
    border: "3px solid #ddd4c8",
    borderTop: "3px solid #c4a882",
    borderRadius: "50%",
    animation: "spin 0.7s linear infinite",
    display: "inline-block",
  },
  loadingText: {
    fontSize: "14px",
    color: "#9c8c7c",
    fontFamily: "'DM Sans', sans-serif",
  },
  root: {
    minHeight: "100vh",
    background: "#f5f0eb",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontFamily: "'DM Sans', sans-serif",
    position: "relative",
    padding: "2rem 1rem",
  },
  bg: {
    position: "absolute",
    inset: 0,
    backgroundImage:
      "linear-gradient(rgba(180,160,140,0.12) 1px, transparent 1px), linear-gradient(90deg, rgba(180,160,140,0.12) 1px, transparent 1px)",
    backgroundSize: "40px 40px",
    pointerEvents: "none",
  },
  layout: {
    display: "flex",
    width: "100%",
    maxWidth: "720px",
    borderRadius: "20px",
    overflow: "hidden",
    boxShadow: "0 4px 40px rgba(120,90,60,0.10)",
    position: "relative",
    animation: "fadeUp 0.45s ease both",
  },
  sidebar: {
    width: "220px",
    flexShrink: 0,
    background: "#3d2e20",
    display: "flex",
    flexDirection: "column",
  },
  sidebarInner: {
    padding: "2rem 1.5rem",
    display: "flex",
    flexDirection: "column",
    gap: "2rem",
  },
  logoRow: { display: "flex", alignItems: "center", gap: "8px" },
  logoMark: {
    width: "32px",
    height: "32px",
    background: "rgba(255,255,255,0.1)",
    borderRadius: "8px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  logoText: {
    fontFamily: "'Lora', serif",
    fontSize: "17px",
    color: "#f5ede2",
    letterSpacing: "-0.3px",
  },
  avatarWrap: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    gap: "6px",
    padding: "1.25rem 0",
    borderTop: "1px solid rgba(255,255,255,0.1)",
    borderBottom: "1px solid rgba(255,255,255,0.1)",
  },
  avatar: {
    width: "60px",
    height: "60px",
    borderRadius: "50%",
    background: "#c4a882",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: "24px",
    fontWeight: "500",
    color: "#3d2e20",
    marginBottom: "4px",
  },
  avatarName: { fontSize: "14px", fontWeight: "500", color: "#f5ede2", textAlign: "center" },
  avatarEmail: { fontSize: "12px", color: "rgba(245,237,226,0.55)", textAlign: "center", wordBreak: "break-all" },
  card: {
    flex: 1,
    background: "#fffefb",
    padding: "2.5rem 2.25rem",
  },
  heading: {
    fontFamily: "'Lora', serif",
    fontSize: "24px",
    fontWeight: "400",
    color: "#2a1f14",
    letterSpacing: "-0.4px",
    marginBottom: "6px",
  },
  subheading: {
    fontSize: "14px",
    color: "#9c8c7c",
    marginBottom: "2rem",
    lineHeight: "1.5",
